toolArgs.file_text:
@namespace sv_5ba417bbc1f941118295c8142d2905f5.Components.Chat
@inject IJSRuntime JS

<div class="message-list" @ref="scrollContainer">
    @if (isLoadingMore)
    {
        <div class="loading-indicator">Loading older messages…</div>
    }
    <div class="sentinel" @ref="topSentinel"></div>

    @foreach (var msg in Messages)
    {
        <MessageItem Message="msg"
                     ReplyCount="GetReplyCount(msg.Id)"
                     OnOpenThread="OnOpenThread"
                     OnReact="OnReact" />
    }
    <div @ref="bottomAnchor"></div>
</div>

@code {
    private ElementReference scrollContainer;
    private ElementReference topSentinel;
    private ElementReference bottomAnchor;
    private DotNetObjectReference<MessageList>? dotNetRef;
    private IJSObjectReference? moduleRef;
    private bool isLoadingMore;
    private bool initialScrollDone;

    [Parameter] public List<Services.Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, int> ThreadReplyCounts { get; set; } = [];
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private int GetReplyCount(int messageId) =>
        ThreadReplyCounts.GetValueOrDefault(messageId, 0);

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            dotNetRef = DotNetObjectReference.Create(this);
            moduleRef = await JS.InvokeAsync<IJSObjectReference>("import", "./js/chat.js");
            await moduleRef.InvokeVoidAsync("observeTopSentinel", topSentinel, dotNetRef);
        }

        if (!initialScrollDone && Messages.Count > 0)
        {
            initialScrollDone = true;
            await ScrollToBottom();
        }
    }

    public async Task ScrollToBottom()
    {
        if (moduleRef is not null)
        {
            await moduleRef.InvokeVoidAsync("scrollToBottom", scrollContainer);
        }
    }

    [JSInvokable]
    public async Task OnTopReached()
    {
        if (isLoadingMore) return;
        isLoadingMore = true;
        StateHasChanged();
        await OnLoadMore.InvokeAsync();
        isLoadingMore = false;
        StateHasChanged();
    }

    public async ValueTask DisposeAsync()
    {
        if (moduleRef is not null)
        {
            await moduleRef.InvokeVoidAsync("cleanup");
            await moduleRef.DisposeAsync();
        }
        dotNetRef?.Dispose();
    }
}

