arguments.file_text:
.chat-layout {
    height: 100vh;
    width: 100vw;
    overflow: hidden;
    display: flex;
}

let observer = null;

export function observeTopSentinel(sentinel, dotNetRef) {
    if (observer) observer.disconnect();

    observer = new IntersectionObserver(
        (entries) => {
            for (const entry of entries) {
                if (entry.isIntersecting) {
                    dotNetRef.invokeMethodAsync("OnTopReached");
                }
            }
        },
        { threshold: 0.1 }
    );

    observer.observe(sentinel);
}

export function scrollToBottom(container) {
    if (container) {
        container.scrollTop = container.scrollHeight;
    }
}

export function cleanup() {
    if (observer) {
        observer.disconnect();
        observer = null;
    }
}

@page "/chat"
@layout ChatLayout
@rendermode InteractiveServer
@using sv_5ba417bbc1f941118295c8142d2905f5.Components.Chat
@using sv_5ba417bbc1f941118295c8142d2905f5.Components.Layout
@using sv_5ba417bbc1f941118295c8142d2905f5.Services
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-container">
    <div class="sidebar-col">
        <ChannelSidebar Channels="channels"
                        ActiveChannelId="selectedChannel?.Id"
                        OnChannelSelected="SelectChannel" />
    </div>

    <div class="main-col @(isThreadOpen ? "with-thread" : "")">
        @if (selectedChannel is not null)
        {
            <MessageArea @ref="messageAreaRef"
                         ChannelName="@selectedChannel.Name"
                         ChannelDescription="@selectedChannel.Description"
                         Messages="messages"
                         ThreadReplyCounts="threadReplyCounts"
                         OnLoadMore="LoadOlderMessages"
                         OnOpenThread="OpenThread"
                         OnReact="HandleReaction"
                         OnSendMessage="SendMessage" />
        }
        else
        {
            <div class="empty-state">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </div>

    @if (isThreadOpen && threadRootMessage is not null)
    {
        <div class="thread-col">
            <ThreadPanel RootMessage="threadRootMessage"
                         ThreadMessages="threadMessages"
                         OnSendReply="SendThreadReply"
                         OnClose="CloseThread" />
        </div>
    }
</div>

@code {
    private List<Channel> channels = [];
    private Channel? selectedChannel;
    private List<Message> messages = [];
    private Dictionary<int, int> threadReplyCounts = [];
    private bool isThreadOpen;
    private Message? threadRootMessage;
    private List<Message> threadMessages = [];
    private MessageArea? messageAreaRef;
    private const int PageSize = 30;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannel(channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        selectedChannel = channels.FirstOrDefault(c => c.Id == channelId);
        if (selectedChannel is null) return;

        CloseThread();
        messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        await BuildThreadReplyCounts();
        await ChatService.MarkChannelReadAsync(channelId);
        RefreshChannelUnread(channelId);

        StateHasChanged();
        if (messageAreaRef is not null)
            await messageAreaRef.ScrollToBottom();
    }

    private async Task LoadOlderMessages()
    {
        if (selectedChannel is null) return;
        var older = await ChatService.GetMessagesAsync(selectedChannel.Id, messages.Count, PageSize);
        if (older.Count > 0)
        {
            messages.InsertRange(0, older);
            await BuildThreadReplyCounts();
        }
    }

    private async Task SendMessage(string content)
