    width: 25%;
    min-width: 280px;
    max-width: 400px;
    flex-shrink: 0;
}

.empty-state {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #72767d;
    font-size: 1.1rem;
}

